			sweep = AnnotationUtility.parseSweepAnnotation(ka);
			if (sweep != null) {		
				field.setValue(sweep);
				field.setCustom();
			} else if (ka != null && !defaultValue.equals(ka.getValue()+"")) {
				field.setValue(ka.getValue()+"");
				field.setCustom();
			}	
